import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import StockTradingScreen from "@screens/stock-trading";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const StockTradingPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Stock Trading App Development", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.stockTradeImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "We build secure, scalable stock trading apps with real-time data, smart analytics, and seamless user experiences for modern investors.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1603",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "How to develop a stock trading app?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Develop a stock trading app by integrating real-time market data, secure APIs, user authentication, trading features, and compliance systems.",
            },
          },
          {
            "@type": "Question",
            name: "How much does it cost to develop a stock trading app?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The cost of developing a stock trading app depends on features, security requirements, real-time data integration, compliance, and overall app complexity.",
            },
          },
          {
            "@type": "Question",
            name: "What is the 7% rule in stock trading?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The 7% rule is a risk management strategy where traders sell a stock if it drops 7% from the buy price to limit losses.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <StockTradingScreen db={db} />
    </Layout_v2>
  );
};

export default StockTradingPage;

export const queryData = graphql`
  query MyQuery {
    stockTradeImg: file(relativePath: { eq: "stock-trading.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "stock-trading-app-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
